// // This module simulates a 1-bit DRAM cell with a write enable signal instead of a word line.
module dram_cell(  
    input wire D,  
    input wire WL,  
    input wire clk,  
    output reg Q  
);  
    reg stored_data;  
    always @(posedge clk) begin  
        if (WL) begin  
            stored_data <= D;  
        end  
        Q <= stored_data;  
    end  
endmodule
